var raw=$input.first().json;
function pj(x){if(typeof x!=='string')return x;try{return JSON.parse(x)}catch(e){return null}}
function isO(v){return v!==null&&typeof v==='object'&&!Array.isArray(v)}
function g(o,k1,k2){if(!isO(o))return null;var v=o[k1];if(v!=null&&v!=='')return v;if(k2){v=o[k2];if(v!=null&&v!=='')return v}return null}
var payload=isO(raw)?raw:{};
if(isO(raw)&&raw.body!==undefined)payload=typeof raw.body==='string'?pj(raw.body):raw.body;
if(!isO(payload))payload={};
var data=isO(payload.data)?payload.data:payload;
if(!isO(data))data=payload;
var tenantId=g(data,'tenantId','tenant_id')||g(payload,'tenantId','tenant_id')||g(raw,'tenantId');
var inventoryId=g(data,'inventoryId','inventory_id')||g(payload,'inventoryId','inventory_id');
if(!tenantId||!inventoryId)return [{json:{_error:true,message:'tenantId et inventoryId requis'}}];
return [{json:{tenantId,inventoryId}}];

var p = $('02. Parser').first().json;
var query = `BEGIN TRANSACTION;
UPDATE inventory_items SET ecart = quantity_counted - quantity_system WHERE inventory_id = '${p.inventoryId}';
UPDATE inventories SET statut = 'finalisee', updated_at = NOW() WHERE id = '${p.inventoryId}' AND tenant_id = '${p.tenantId}';
UPDATE stock_levels sl SET quantity = sl.quantity + ii.ecart, updated_at = NOW() FROM inventory_items ii, inventories i WHERE ii.inventory_id = i.id AND i.id = '${p.inventoryId}' AND sl.article_id = ii.article_id AND sl.site_id = i.site_id AND sl.tenant_id = '${p.tenantId}' AND ii.ecart != 0;
INSERT INTO stock_movements (id, tenant_id, article_id, site_id, type_mouvement, quantity, date_operation, reference, notes, created_at, updated_at) SELECT gen_random_uuid(), '${p.tenantId}', ii.article_id, i.site_id, 'inventaire', ii.ecart, NOW(), i.id, 'Ajustement inventaire', NOW(), NOW() FROM inventory_items ii, inventories i WHERE ii.inventory_id = i.id AND i.id = '${p.inventoryId}' AND ii.ecart != 0;
COMMIT;`;
return [{json:{query}}];
